// netlify/functions/tax-interview.js
// AI-powered "missed deductions" analysis using Haiku.
// Takes what the user declared and returns suggestions for what they may have forgotten.
// Auth required. No financial numbers are generated by AI — only qualitative suggestions.

import Anthropic from '@anthropic-ai/sdk'

const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY })

const FORMAT_RULES = `Never use em dashes (—). Never use tilde (~). Never use markdown bold (**text**). Write in plain prose. Keep suggestions concise and specific to South Africa.`

export const handler = async (event) => {
  if (event.httpMethod !== 'POST') return { statusCode: 405, body: 'Method not allowed' }

  try {
    const authHeader = event.headers.authorization || event.headers.Authorization
    if (!authHeader?.startsWith('Bearer ')) return { statusCode: 401, body: 'Unauthorized' }

    const { incomeType, answers = {} } = JSON.parse(event.body || '{}')
    if (!incomeType || !['rental', 'freelance'].includes(incomeType)) {
      return { statusCode: 400, body: JSON.stringify({ error: 'Invalid income type' }) }
    }

    let systemPrompt = ''
    let userPrompt = ''

    if (incomeType === 'rental') {
      const declared = []
      if (answers.bondInterest > 0) declared.push(`bond interest R${answers.bondInterest}`)
      if (answers.rates > 0) declared.push(`rates and taxes R${answers.rates}`)
      if (answers.agentFees > 0) declared.push(`agent fees R${answers.agentFees}`)
      if (answers.insurance > 0) declared.push(`insurance R${answers.insurance}`)
      if (answers.repairs > 0) declared.push(`repairs R${answers.repairs}`)
      if (answers.garden > 0) declared.push(`garden services R${answers.garden}`)
      if (answers.security > 0) declared.push(`security R${answers.security}`)
      if (answers.advertising > 0) declared.push(`advertising R${answers.advertising}`)
      if (answers.levies > 0) declared.push(`levies R${answers.levies}`)

      const notDeclared = [
        !answers.bondInterest && 'bond interest (only the interest portion, not capital repayment)',
        !answers.rates && 'municipal rates and taxes',
        !answers.agentFees && 'estate agent or property management fees',
        !answers.insurance && 'homeowners insurance (not contents insurance)',
        !answers.repairs && 'repairs and maintenance (not improvements)',
        !answers.garden && 'garden services',
        !answers.security && 'security costs',
        !answers.advertising && 'tenant advertising costs',
        !answers.levies && 'body corporate levies (if sectional title)',
      ].filter(Boolean)

      systemPrompt = `You are a South African tax assistant helping a rental property owner identify deductions they may have missed. ${FORMAT_RULES} Be brief, practical, and specific to South African rental property tax rules. Only mention items that are actually SARS-compliant deductions. Do not invent numbers.`

      userPrompt = `A South African taxpayer has declared the following rental property expenses for the year: ${declared.length ? declared.join(', ') : 'nothing yet'}.

They did NOT declare: ${notDeclared.join(', ')}.

Give them 2-3 short, specific suggestions about what they should check or gather receipts for before seeing their accountant. Focus on the most commonly forgotten items. Also remind them of the repair vs improvement distinction if they claimed repairs. Keep your response under 100 words.`
    }

    if (incomeType === 'freelance') {
      const declared = []
      if (answers.profSubscriptions > 0) declared.push(`professional subscriptions R${answers.profSubscriptions}`)
      if (answers.software > 0) declared.push(`software R${answers.software}`)
      if (answers.phone > 0) declared.push(`phone/data R${answers.phone}`)
      if (answers.travel > 0) declared.push(`business travel R${answers.travel}`)
      if (answers.training > 0) declared.push(`training R${answers.training}`)
      if (answers.insurance > 0) declared.push(`professional indemnity insurance R${answers.insurance}`)
      if (answers.accountant > 0) declared.push(`accountant fees R${answers.accountant}`)

      const notDeclared = [
        !answers.profSubscriptions && 'professional body membership fees',
        !answers.software && 'business software subscriptions',
        !answers.phone && 'business proportion of phone and data costs',
        !answers.travel && 'business travel expenses (not commuting)',
        !answers.training && 'professional development and training costs',
        !answers.insurance && 'professional indemnity insurance',
        !answers.accountant && 'accountant fees for freelance work',
      ].filter(Boolean)

      systemPrompt = `You are a South African tax assistant helping a freelancer or consultant identify deductions they may have missed. ${FORMAT_RULES} Be brief, practical, and specific. Only mention items that are SARS-compliant deductions for self-employed persons. Do not invent numbers.`

      userPrompt = `A South African freelancer or consultant has declared the following business expenses for the year: ${declared.length ? declared.join(', ') : 'nothing yet'}.

They did NOT declare: ${notDeclared.join(', ')}.

Give them 2-3 short, specific suggestions about deductions to check or gather receipts for. Also flag that they are likely a provisional taxpayer with bi-annual submission deadlines. Keep your response under 100 words.`
    }

    const response = await client.messages.create({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 200,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }],
    })

    const suggestion = response.content[0]?.text || ''

    return {
      statusCode: 200,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ suggestion }),
    }
  } catch (err) {
    console.error('tax-interview error:', err)
    return { statusCode: 500, body: JSON.stringify({ error: 'Could not generate suggestions.' }) }
  }
}
